import React from 'react';

const Experience = () => {
  return (
    <section id="experience" className="section">
      <div className="container">
        <h2>Professional Experience</h2>
        <div className="experience-timeline">
          <div className="experience-item">
            <h3>Senior Civil Engineer</h3>
            <p className="company">ABC Engineering Firm</p>
            <p className="date">2020 - Present</p>
            <p>Lead structural design for commercial and residential projects, managing teams of up to 8 engineers.</p>
          </div>
          <div className="experience-item">
            <h3>Civil Engineer</h3>
            <p className="company">XYZ Infrastructure</p>
            <p className="date">2018 - 2020</p>
            <p>Performed site inspections, prepared cost estimates, and coordinated with contractors on public works projects.</p>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Experience;
